THREE.JS + REACT THREE FIBER + @REMOTION/THREE

For 3D scenes in Remotion, use <ThreeCanvas> from @remotion/three (NOT regular <Canvas>).

SETUP:
```tsx
import { ThreeCanvas } from '@remotion/three';
import { useCurrentFrame, useVideoConfig } from 'remotion';

const Scene3D: React.FC = () => {
  const frame = useCurrentFrame();
  const { width, height } = useVideoConfig();
  return (
    <ThreeCanvas
      orthographic={false}
      width={width}
      height={height}
      style={{ width: '100%', height: '100%' }}
      camera={{ position: [0, 0, 5], fov: 75 }}
    >
      <ambientLight intensity={0.5} />
      <pointLight position={[10, 10, 10]} />
      <MyMesh />
    </ThreeCanvas>
  );
};
```

GEOMETRY: boxGeometry, sphereGeometry, cylinderGeometry, coneGeometry, torusGeometry, planeGeometry
MATERIALS: meshStandardMaterial (PBR), meshPhongMaterial (shiny), meshBasicMaterial (unlit), meshNormalMaterial
LIGHTS: ambientLight, pointLight, directionalLight, spotLight
CAMERA: Animate camera position/rotation using useCurrentFrame() + interpolate()

ANIMATION PATTERN:
const rotation = interpolate(frame, [0, 90], [0, Math.PI * 2]);
<mesh rotation={[0, rotation, 0]}>
  <boxGeometry args={[1, 1, 1]} />
  <meshStandardMaterial color="#58a6ff" metalness={0.5} roughness={0.3} />
</mesh>
